class Solution:
    def countWays(self, ranges):
        MOD = 10 ** 9 + 7
        n = len(ranges)
        parent = list(range(n))
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        def union(a, b):
            ra, rb = find(a), find(b)
            if ra != rb:
                parent[ra] = rb
        def overlaps(a, b):
            return a[0] <= b[1] and b[0] <= a[1]
        for i in range(n):
            for j in range(i + 1, n):
                if overlaps(ranges[i], ranges[j]):
                    union(i, j)
        clusters = len({find(i) for i in range(n)})
        return pow(2, clusters, MOD)

