class Solution:
    def countWays(self, ranges):
        MOD = 10 ** 9 + 7
        ranges = sorted(ranges)
        groups = 0
        cur_end = -1
        for s, e in ranges:
            if s > cur_end:
                groups += 1
                cur_end = e
            else:
                cur_end = max(cur_end, e)
        return pow(2, groups, MOD)

